 using Microsoft.ML;
 using Microsoft.Extensions.ML;
 using ChurnPredictor.Models;

 var builder = WebApplication.CreateBuilder(args);

 // Train the model and save to disk
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
 var csvPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 TrainAndSaveModel(csvPath, modelPath);

 // Register a thread-safe PredictionEnginePool (never use a singleton PredictionEngine)
 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST to /predict");

 app.MapPost("/predict", (
     PredictionEnginePool<CustomerData, ChurnPrediction> pool,
     CustomerData customer) =>
 {
     var prediction = pool.Predict(customer);
     return Results.Ok(new
     {
         WillChurn = prediction.Churned,
         prediction.Probability,
         prediction.Score,
     });
 });

 app.Run();

 static void TrainAndSaveModel(string dataPath, string modelPath)
 {
     var mlContext = new MLContext(seed: 42);

     // Parse CSV and map "Yes"/"No" → boolean label
     var records = File.ReadAllLines(dataPath)
         .Skip(1)
         .Select(line =>
         {
             var parts = line.Split(',');
             return new CustomerData
             {
                 Age = float.Parse(parts[0]),
                 Income = float.Parse(parts[1]),
                 Region = parts[2].Trim(),
                 PurchaseHistory = float.Parse(parts[3]),
                 Churned = parts[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase),
             };
         })
         .ToList();

     var data = mlContext.Data.LoadFromEnumerable(records);

     // Train/test split — never evaluate on training data
     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

     // Build the training pipeline
     var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(CustomerData.Age),
             nameof(CustomerData.Income),
             "RegionEncoded",
             nameof(CustomerData.PurchaseHistory)))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
             labelColumnName: "Label", featureColumnName: "Features"));

     var model = pipeline.Fit(split.TrainSet);

     // Evaluate and log metrics (guard against tiny datasets lacking both classes)
     var predictions = model.Transform(split.TestSet);
     try
     {
         var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
         Console.WriteLine($"[ML.NET] AUC: {metrics.AreaUnderRocCurve:F4}  " +
                           $"F1: {metrics.F1Score:F4}  " +
                           $"Accuracy: {metrics.Accuracy:F4}");
     }
     catch (ArgumentOutOfRangeException)
     {
         Console.WriteLine("[ML.NET] Warning: Test set too small for full evaluation " +
                           "(needs both positive and negative examples). Add more data.");
     }

     // Save the model
     mlContext.Model.Save(model, data.Schema, modelPath);
     Console.WriteLine($"[ML.NET] Model saved to {modelPath}");
 }

